output.rtl/caesar_cipher.sv:
module caesar_cipher (
    input [7:0] input_char,
    input [3:0] key,
    output reg [7:0] output_char
);

// Define a constant for the ASCII value of 'a'
localparam ASCII_a = 97;

always @(*) begin
    // Check if input character is uppercase (A-Z)
    if (input_char >= 65 && input_char <= 90) begin
        // Calculate the new alphabet index based on key and modulo 26
        output_char = (input_char - 65 + key);
        // Wrap around to 'A' if the result is greater than Z
        if (output_char > 90) begin
            output_char = output_char - 26;
        end
    end
    // Check if input character is lowercase (a-z)
    else if (input_char >= ASCII_a && input_char <= 122) begin
        // Calculate the new alphabet index based on key and modulo 26
        output_char = ((input_char - ASCII_a + key);
        // Wrap around to 'a' if the result is greater than z
        if (output_char > 122) begin
            output_char = output_char - 26;
        end
    end
    else begin
        // No alphabetic shift required, output character unchanged
        output_char = input_char;
    end
end

endmodule

output.rtl/car_parking_system.sv:
module car_parking_system #(parameter TOTAL_SPACES = 12) (
    input clk,
    input reset,
    input vehicle_entry_sensor,
    input vehicle_exit_sensor,
    output reg [log2(TOTAL_SPACES)-1:0] available_spaces,
    output reg [log2(TOTAL_SPACES)-1:0] count_car,
    output reg led_status,
    output reg [6:0] seven_seg_display_available_tens,
    output reg [6:0] seven_seg_display_available_units,
    output reg [6:0] seven_seg_display_count_tens,
    output reg [6:0] seven_seg_display_count_units
);

// Define state variables
reg [1:0] current_state;
reg [1:0] next_state;
reg [log2(TOTAL_SPACES)-1:0] available; // Available Spaces counter
reg [log2(TOTAL_SPACES)-1:0] count; // Count of cars currently parked

// Define state encoding
parameter Idle = 2'b00;
parameter EntryProcessing = 2'b01;
parameter ExitProcessing = 2'b10;
parameter Full = 2'b11;

initial begin
    // Reset the system
    current_state <= Idle;
    next_state <= Idle;
    available <= TOTAL_SPACES;
    count <= 0;
    led_status <= 1; // Initialize to Parking Available status
    seven_seg_display_available_tens <= 7'b0000001;
    seven_seg_display_available_units <= 7'b1000000;
    seven_seg_display_count_tens <= 7'b0000001;
    seven_seg_display_count_units <= 7'b1000000;
end

always @(posedge clk) begin
    if (reset) begin
        // Reset the system
        current_state <= Idle;
        next_state <= Idle;
        available <= TOTAL_SPACES;
        count <= 0;
        led_status <= 1; // Initialize to Parking Available status
        seven_seg_display_available_tens <= 7'b0000001;
        seven_seg_display_available_units <= 7'b1000000;
        seven_seg_display_count_tens <= 7'b0000001;
        seven_seg_display_count_units <= 7'b1000000;
    end else begin
        // Update the state machine
        current_state <= next_state;

        case (current_state)
            Idle: begin
                if (vehicle_entry_sensor) begin
                    next_state <= EntryProcessing;
                    available -= 1;
                    count += 1;
                    led_status <= 0; // Parking full status
                    seven_seg_display_available_tens <= 7'b1000000;
                    seven_seg_display_count_tens <= count / 10;
                    seven_seg_display_count_units <= (count % 10);
                end else if (vehicle_exit_sensor) begin
                    next_state <= ExitProcessing;
                    increment_spaces();
                    decrement_cars();
                    led_status <= 1; // Parking Available status
                end
            end
            EntryProcessing: begin
                next_state <= Full;
                available -= 1;
                count += 1;
                led_status <= 0; // Parking full status
                seven_seg_display_available_tens <= 7'b1000000;
                seven_seg_display_count_tens <= (~count[log2(TOTAL_SPACES)-2:0] & ~count);
                seven_seg_display_count_units <= count[log2(TOTAL_SPACES)-1];
        // No need to update the display for the number of cars as we incremented it in EntryProcessing state
                    end
            ExitProcessing: begin
                next_state <= Idle;
                decrement_spaces();
                decrement_cars();
                led_status <= 1; // Parking Available status

                seven_seg_display_available_tens <= 7'b0000001;
                seven_seg_display_available_units <= seven_seg_display_count_tens[6:0];
                    // TODO: Update the display if cars are present
                seven_seg_display_count_tens <= seven_seg_display_count_tens;
                seven_seg_display_count_units <= seven_seg_display_count_units;
            end
        endcase
    end
end

// Helper functions for updating the state machine
function logic increment_spaces; return logic; integer space;
    input [log2(TOTAL_SPACES)-1:0] count_upward;
    reg [log2(TOTAL_SPACES)-1:0] count;
    begin
        count >= 1 ? (space = next(count_upward)) : (space = TOTAL_SPACES); // Wrap around at max
        increment_spaces <= space!=current || space!=next(count, count_upward) || (count + 1) != current;   // Check if we need to increment spaces
    end endfunction

function logic decrement_spaces; return logic; integer space;
    input [log2(TOTAL_SPACES)-1:0] count_downward;
    reg [log2(TOTAL_SPACES)-1:0] count;
    begin
        decrement_spaces <= (count[log2(TOTAL_SPACES)-2]-1)!=(count[log2(TOTAL_SPACES)-1]) ||  // Check if we need to decrement spaces, no overflowing or underflowing
            next(count_downward)!=(count != 0) || count + -1 != current;   
    end endfunction

function logic decrement_cars; return logic; integer car;
    reg [log2(TOTAL_SPACES)-1:0] count_max;
    begin
        decrement_cars <= decrement_spaces(count-car) && total_space(current) ? 1 : 0;   // Check if we need to decrement cars
    end endfunction

function logic increment_cars; return logic; integer car;
    reg [log2(TOTAL_SPACES)-1:0] count_car;
    register regs[5:0]; // Segments encoder of the display
    assign seven_seg_display_count_tens = {regs[6], regs[5], regs[4]} + 1'b0;        // Add one to the count tens digit
    assign seven_seg_display_count_units = {regs[3], regs[2], regs[1], regs[0]};      // Encoder segment of the count units digit
    begin
        // Calculate the number of cars in real time from the current parking space status
        for (car=count-1; car>=0 && decrement_spaces(current, 1)!=0; car=car-1) count_max <= total_space(~current) ? 2'h0 : ~TOTAL_SPACES;            // Scan the parking space count from maximum to minimum as this should be the first one available

        increment_cars <= decrement_spaces(count_max) || increament_spaces(count) ;   // Check if we need to increment cars and update the display accordingly or not
    end endfunction

function logic total_space; return logic; integer count;
    begin
        total_space <= (current[log2(TOTAL_SPACES)-1]&TOTAL_SPACES) != current;       // Check if the most significant bit is 0 or not, where we know all parking space are available
    end endfunction

always @* begin
    count_max <= total_space(current) ? log2(TOTAL_SPACES-1) : log2(`log2(TOTAL_SPACES)); // Count max can be any place in the parking lot. log2 for binary to decimal conversions
    current <= increment_cars && count < count_max ? current + 1'b1 : 
              decrement_spaces == total_space(current) ? TOTAL_SPACES - 1'b1 : current; // If we were able to increament cars the counter should be updated, else if all parking spaces are free set parking status to full
    count <= increment_cars && count < total_spaces-1 ? (count == 0 && decrement_spaces) ? 0 : count + 1'b1 : decrement_cars-(current==0)?1'b0:--count;     // If we were able to increament cars the counter should be updated, else if all parking spaces are full set parking status to Parking Available
end

assign seven_seg_display_available_tens = 7'b0000001;
assign seven_seg_display_count_units = (count % 10)+2'h4; // O(TOTAL_SPACES); if more significant bit is set, count is greater than 9 and needs to shifted on its own.
endmodule

output.rtl/clock_divider.sv:
module rst_ff(input clk, rst_n, output reg out);
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            out <= 1'b0;
        end else begin
            out <= #1 ~out;
        end
    end
endmodule

// This clock divider uses an FSM. The state encoding is as follows:
//  00: Counter at '0'.
//  01: Counter at '2', first counter period finished.
//  10: Counter at '4', second counter period finished.
//  11: Counter at '8' (or 7, depending on the division factor), third counter period finished.
// In a real system, one would typically use two counters (one for dividing by two and one for dividing by four/eight) instead. The FSM is made more complex in this case because it has to wait for the next rising edge of the input clock, but it could be much simpler otherwise.
module clock_divider(input clk, input rst_n, input [1:0] sel, output reg clk_out);
    localparam IDLE = 2'b00;
    localparam COUNT8_FINISHED = 2'b11;
    reg [2:0] state;

    reg [3:0] count;
    wire clk_divided = (count == 4'd7) ? ~count[3] : 1'b0;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= IDLE;
            count <= 4'd0;
            clk_out <= 1'b0;
        end else begin
            // State machine
            case (state)
                IDLE:
                    if (sel == 2'b00)
                        state <= COUNT8_FINISHED;
                COUNT8_FINISHED:
                    begin
                        if (sel == 2'b10) // Divide by 4
                            state <= IDLE;
                        else if (sel == 2'b10) // Divide by 8
                            state <= {cnt[3], cnt[2:0]};
                    end
            endcase

            if (sel != IDLE) begin
                count <= (count + 4'd1) % 5;
                clk_out <= clk_divided;
            end else begin
                count <= 4'd0;
                clk_out <= 1'b0;
            end
        end
    end
endmodule

output.rtl/signed_comparator.sv:
Module Name: signed_comparator WIDTH: 5 -------------------- mode, enable, greater, lesser, equal inputs (in order): mode (active high): selects the comparison mode (1 for signed mode, 0 for magnitude mode); if magnitude mode is selected, the MSB of the input registers will be ignored. enable (active high): enables or disables the comparison logic in case the value we want to compare is unknown and it's possible that we really want to keep the values as-is; lesser or greater: these signals are active low, indicating if A < B or A > B. 0 will mean equality. equal (active high): the input registers can be kept as-is because they are equivalent equality logic is not used here since we need an enable signal to make the comparison happen. inputs: A and B have a WIDTH bits width (including the MSB when mode == 1; this is why signed mode does not work for widths < 8), and both are registered; i_mode and i_enable can be freely synthesizable if the FPGA tools support them. output signals: o_greater, o_less, o_equal. -------------------- module signed_unsigned_comparator(
    input [WIDTH-1:0] i_A,
    input [WIDTH-1:0] i_B,
    input i_mode,
    input i_enable,
    output reg o_greater,
    output reg o_less,
    output reg o_equal
);

always @(*) begin
    if (i_enable) begin // comparison is requested
        if (i_mode) begin // signed mode
            if ((i_A[WIDTH-1] == 1 && i_B[WIDTH-1] == 0) || (i_A[WIDTH-1] == 0 && i_B[WIDTH-1] == 1)) begin
                o_greater = 1;
                o_less = 0;
                o_equal = 0;
            end else if ((i_A[WIDTH-1] == 1) && (i_B[WIDTH-1] == 0)) begin // A has a negative sign, B doesn't
                o_greater = 1;
                o_less = 0;
                o_equal = 0;
            end else if ((~i_A[WIDTH-1]) && i_B[WIDTH-1]) begin // A has a positive sign, B doesn't
                o_greater = 0;
                o_less = 1;
                o_equal = 0;
            end else if (i_A == i_B) begin
                o_greater = 0;
                o_less = 0;
                o_equal = 1;
            end else begin // neither A nor B have a sign, just treat them as unsigned numbers
                if (i_A > i_B) begin
                    o_greater = 1;
                    o_less = 0;
                    o_equal = 0;
                end else if (i_A < i_B) begin
                    o_greater = 0;
                    o_less = 1;
                    o_equal = 0;
                end else begin // i_A == i_B
                    o_greater = 0;
                    o_less = 0;
                    o_equal = 1;
                end
            end
        end else begin // magnitude mode
            if (i_A > i_B) begin // B < A, i.e. lesser
                o_greater = 0;
                o_less = 1;
                o_equal = 0;
            end else if (i_A < i_B) begin // A < B, greater
                o_greater = 1;
                o_less = 0;
                o_equal = 0;
            end else begin // i_A == i_B
                o_greater = 0;
                o_less = 0;
                o_equal = 1;
            end
        end
    end else begin // comparison is disabled, output low signals regardless of the inputs
        o_greater = 0;
        o_less = 0;
        o_equal = 0;
    end
end

// synthesis attribute to work around tools that do not yet understand i_mode/i_enable
initial begin
    $synthesis_synopsys_compatibility("mode");
end

endmodule

