module sync_pos_neg_edge_detector (
    input i_clk,
    input i_rstb,
    input i_detection_signal,
    output o_positive_edge_detected,
    output o_negative_edge_detected
);

reg positive_edge_last;
reg negative_edge_last;

wire rising_edge = (i_detection_signal & ~positive_edge_last) | (~i_detection_signal & positive_edge_last);
wire falling_edge = (i_detection_signal & ~negative_edge_last) | (~i_detection_signal & negative_edge_last);

assign o_positive_edge_detected = rising_edge;
assign o_negative_edge_detected = falling_edge;

always @(posedge i_clk or negedge i_rstb) begin
    if (!i_rstb) begin
        positive_edge_last <= 0;
        negative_edge_last <= 0;
    end else begin
        positive_edge_last <= rising_edge;
        negative_edge_last <= falling_edge;
    end
end

endmodule

output.rtl/ethernet_parser.v:
module ethernet_parser(
    input clk,
    input rst,
    input vld,
    input sof,
    input [31:0] data,
    output ack,
    output reg [15:0] field,
    output reg field_vld,
    output reg [4:0] beat_cnt
);

// Beat counter
reg [4:0] beat_cnt;
always @(posedge clk) begin
    if (rst) begin
        beat_cnt <= 0;
        field_vld <= 0;
    end else if (sof) begin // Start of new frame detected, reset counters and prepare extraction
        beat_cnt <= 0;
        field_vld <= 0;
    end else if (vld) begin
        beat_cnt <= beat_cnt + 1;
    end
end

// Temporary storage
reg [15:0] temp_extracted_field;
always @(posedge clk) begin
    if (rst) begin
        temp_extracted_field <= 0;
    end else if (sof && vld && beat_cnt == 1) begin // 2nd beat of the burst, capture most significant bytes
        temp_extracted_field <= data[31:16];
    end
end

// State machine
reg [1:0] state;
parameter IDLE = 2'd0;
parameter EXTRACTING = 2'd1;
parameter DONE = 2'd2;
parameter FAIL_FINAL = 2'd3;
always @(posedge clk) begin
    if (rst) begin
        state <= IDLE;
        field <= 0;
        beat_cnt <= 0;
    end else if (sof) begin // Start of new frame detected, reset counters and prepare extraction
        state <= IDLE;
        field <= 0;
        beat_cnt <= 0;
        field_vld <= 0;
    end else if (state == IDLE && vld) begin
        state <= EXTRACTING;
    end else if (state == EXTRACTING && vld) begin
        beat_cnt <= beat_cnt + 1;
        if (beat_cnt == 1) begin // 2nd beat of the burst, capture most significant bytes
            temp_extracted_field <= data[31:16];
            state <= DONE;
        end else if (eof) begin // End of burst detected, reset state and wait for next burst
            state <= FAIL_FINAL;
        end
    end else if (state == FAIL_FINAL && eof) begin
        field_vld <= 0;
        beat_cnt <= 0;
        state <= IDLE;
    end else if (state != DONE) begin // For all states expect Done, output is cleared
        temp_extracted_field <= 0;
    end
end

// Assignments
assign ack = 1'b1;
always @(posedge clk) begin
    if (rst) begin
        field <= 0;
    end else if (state == DONE & ~eof) begin
        field <= temp_extracted_field;
        field_vld <= 1'b1;
    end else if (eof && state != FAIL_FINAL) begin
        field_vld <= 0;
    end
end

endmodule

output.rtl/apb_controller.sv:
module apb_controller (
  input clk,
  input reset_n,
  input select_a_i,
  input select_b_i,
  input select_c_i,
  input [31:0] addr_a_i,
  input [31:0] data_a_i,
  input [31:0] addr_b_i,
  input [31:0] data_b_i,
  input [31:0] addr_c_i,
  input [31:0] data_c_i,
  output reg apb_psel_o,
  output reg apb_penable_o,
  output reg apb_pwrite_o,
  output reg [31:0] apb_paddr_o,
  output reg [31:0] apb_pwdata_o,
  input apb_pready_i
);

  // Internal signals
  reg [1:0] state;
  reg [31:0] timeout;

  always @(posedge clk, negedge reset_n) begin
    if (~reset_n) begin
      state <= 2'b00; // IDLE
      apb_psel_o <= 0;
      apb_penable_o <= 0;
      apb_pwrite_o <= 0;
      apb_paddr_o <= 0;
      apb_pwdata_o <= 0;
      timeout <= 4'b0; // Reset timeout counter.
    end else begin
      case (state)
        2'b00: // IDLE state
          if ({select_a_i, select_b_i, select_c_i} != 3'b0) begin
            if ({select_a_i, select_b_i, select_c_i} == 3'b10) begin
              // Only Event A is active
              apb_psel_o <= 1;
              apb_paddr_o <= addr_a_i;
              apb_pwdata_o <= data_a_i;
            end
            else if ({select_a_i, select_b_i, select_c_i} == 3'b01) begin
              // Only Event B is active
              apb_psel_o <= 1;
              apb_paddr_o <= addr_b_i;
              apb_pwdata_o <= data_b_i;
            end
            else if ({select_a_i, select_b_i, select_c_i} == 3'b00) begin
              // Only Event C is active
              apb_psel_o <= 1;
              apb_paddr_o <= addr_c_i;
              apb_pwdata_o <= data_c_i;
            end
            state <= 2'b01; // SETUP State
          end // if select signal asserted
        2'b01: // SETUP state
          begin
            apb_penable_o <= 1;
            state <= 2'b10; // ACCESS State
          end
        2'b10: // ACCESS State
          if (apb_pready_i) begin
            apb_psel_o <= 0;
            apb_penable_o <= 0;
            timeout <= 4'b0; // Reset timeout counter.
            if ({select_a_i, select_b_i, select_c_i} != 3'b0) begin
              state <= 2'b00; // IDLE State
            end
          end else if (timeout < 4'hF) begin
            timeout <= timeout + 1;
            apb_penable_o <= 1;
          end else begin
            apb_psel_o <= 0;
            apb_penable_o <= 0;
            state <= 2'b00; // IDLE State
          end // if (apb_pready_i || timeout == 4'hF)
        default: state <= 2'b00; // Default to IDLE.
      endcase
    end
  end
endmodule

output.rtl/factorial.sv:
module factorial_computation (
    input clk,
    input arst_n,
    input [4:0] num_in,
    input start,
    output reg busy,
    output reg [63:0] fact,
    output reg done
);

    // Define State Enum for FSM
    typedef enum {
        Idle,
        Bussy,
        Done
    } state_t;

    // Define FSM Signals and Regs
    reg [2:0] state;
    parameter Idle = 3'd0;
    parameter Bussy = 3'd1;
    parameter Done = 3'd2;

    always @ (posedge clk or negedge arst_n) begin
        if (!arst_n) begin
            state <= Idle;
            busy <= 0;
            fact <= 1;
            done <= 0;
            fact <= 1;
        end else begin
            case (state)
                Idle: begin
                    if (start == 1 && num_in < 32) begin
                        state <= Bussy;
                        busy <= 1;
                    end
                end
                Bussy: begin
                    fact <= fact * (num_in+1);
                    num_in = num_in - 1;
                    if (num_in == 0) begin
                        state <= Done;
                        busy <= 0;
                        done <= 1;
                    end else begin
                        fact <= fact * (num_in+1);
                        num_in = num_in - 1;
                    end
                end
                Done: begin
                    done <= 0;
                end
            endcase
        end
    end
endmodule

output.rtl/fifo_async.sv:
module fifo_async(
  input wire w_clk,
  input wire w_rst,
  input wire w_inc,
  input wire [DATA_WIDTH-1:0] w_data,
  output reg w_full,
  input wire r_clk,
  input wire r_rst,
  input wire r_inc,
  output reg r_empty,
  output reg [ DATA_WIDTH-1 : 0 ] r_data
);

parameter DEPTH = 4;

reg [$clog2(DEPTH)-1:0] write_ptr = 1;
reg [$clog2(DEPTH)-1:0] read_ptr = 1;
reg full_reg, empty_reg, wg_rst;
wire is_empty = (write_ptr == read_ptr);
wire is_full = ((write_ptr & ~read_ptr[DATA_WIDTH-2:0]) |
                (~write_ptr[DATA_WIDTH-1] & read_ptr));
wire wg_sync;
wire rg_sync;

// Write Gray counter
always @(posedge w_clk or posedge w_rst) begin
  if (w_rst) begin
    write_ptr <= 1;
  end else if (w_inc & ~wg_rst && ~wg_sync) begin
    write_ptr <= write_ptr ^ {write_ptr[DATA_WIDTH-2:0], w_full};
  end
end

always @(negedge w_clk or posedge w_rst) begin
  if (w_rst) begin
    wg_rst <= 1'b0;
  end else if (~wg_sync & r_inc) begin
    wg_rst <= 1'b1;
  end
end

always @(negedge r_clk or posedge read_ptr[DATA_WIDTH-2:0]) begin
  if (r_full & ~wg_sync) begin
    full_reg <= wg_rst;
  end else begin
    full_reg <= is_full;
  end
end

// Read Gray counter
always @(posedge r_clk or posedge r_rst) begin
  if (r_rst) begin
    read_ptr <= {DEPTH{1'b0}};
  end else if (r_inc & full_reg) begin
    read_ptr <= read_ptr ^ {1'b0, read_ptr[DATA_WIDTH-1:1]};
  end
end

always @(negedge r_clk or posedge read_ptr > wk_cnt) begin
  if (r_full | ((read_ptr & ~wk_cnt) != {(DEPTH){1'b0}})) begin
    empty_reg <= 1'b1;
  end else begin
    empty_reg <= is_empty;
  end
end

assign rg_sync = (read_ptr >= write_ptr);
assign wk_cnt = {DEPTH-1{1'b0}} - read_ptr + write_ptr[DATA_WIDTH-2:0];
assign r_data = rg_sync ? read_ptr[DATA_WIDTH - 1:0] : w_full;
always @(negedge r_clk or posedge empty_reg) begin
  r_empty <= ~empty_reg;
end

always @(negedge r_clk or posedge full_reg) begin
  full_reg <= 1'b0;
end

initial wg_rst = 1'b0;
initial rg_sync = 1'b0;
initial empty_reg = 1'b1;
initial write_ptr[0] = 1'b0;
initial read_ptr[0] = 1'b0;
initial full_reg = 1'b0;
initial r_empty = 1'b0;
endmodule

output.rtl/FILO_RTL.sv:
module FILO_RTL (
  input clk,
  input reset,
  input push,
  input pop,
  input [`DATA_WIDTH-1:`DATA_WIDTH] data_in,
  output reg [`DATA_WIDTH-1:`DATA_WIDTH] data_out,
  output reg full,
  output reg empty
);

parameter DATA_WIDTH = 8;
parameter FILO_DEPTH = 16;

// Internal state variables
reg [`DATA_WIDTH-1:`DATA_WIDTH] mem [0:FILO_DEPTH-1]; // memory buffer
reg [$clog2(FILO_DEPTH)-1:0] top; // current top of the stack pointer

always @ (posedge clk) begin
  if (reset) begin
    // reset operation
    top <= 0;
    full <= 0;
    empty <= 1;
  end else begin
    if (push && !full) begin
      mem[top] <= data_in;
      top <= top + 1;
      if (top == FILO_DEPTH) begin
        full <= 1;
      end
      empty <= 0;
    end

    if (pop && !empty) begin
      data_out <= mem[top-1];
      top <= top - 1;
      if (top == 0) begin
        empty <= 1;
      end
      full <= 0;
    end
  end
end

endmodule

output.rtl/hamming_code_tx_for_4bit.sv:
Module Name: hamming_code_tx_for_4bit
Version: 0.1
Authors: Yunxiang "Annie" Hu (yan@sandia.gov)
Date Created: 2023-05-09 21:29:12 UTC
SRL #: 68311X_V64E_B12XE/Virtex6-SL FPGA
//---------------------------------------------------------------------------
module hamming_code_tx_for_4bit(
    input [3:0] data_in,        // Original data to be encoded and transmitted
    output reg [7:0] data_out   // 8-bit encoded signal with padded redundant bit (0), 3 parity bits (padded with 1s) and the original input bits.
);

// Encoding module logic
always @* begin
    // Calculate 2 parity bits based on even parity at positions 0, 1, 3 of data_in bits using XOR operation
    data_out[1] = ^data_in;
    data_out[2] = ^{{1'b0, data_in[0], data_in[2]}};

    // Preserve the ordering and values of input bits by assigning them directly to the 4 most significant bits in data_out
    data_out[3:0] = {data_in[3:1], 1'b0};
end

// End of module logic
endmodule

output.rtl/load_store_unit.sv:
module load_store_unit (
    input wire clk,
    input wire rst_n,
    input wire dmem_req_o,
    output wire dmem_gnt_i,
    input wire [31:0] dmem_req_addr_o,
    input wire [3:0] dmem_req_be_o,
    input wire [31:0] dmem_req_wdata_o,
    output wire [31:0] dmem_rsp_rdata_i,
    output wire dmem_rvalid_i,
    input wire dmem_rready_i,
    input wire ex_if_req_i,
    input wire ex_if_we_i,
    input wire [1:0] ex_if_type_i,
    input wire [31:0] ex_if_wdata_i,
    output wire ex_if_ready_o,
    input wire [31:0] ex_if_addr_offset_i,
    output wire [31:0] ex_if_req_addr_i,
    output wire [3:0] ex_if_req_be_o,
    output wire ex_if_req_we_o,
    input wire [31:0] ex_if_rsp_rdata,
    output wire [31:0] wb_if_rdata_o,
    output wire wb_if_rvalid_o,
    input wire wb_if_ready_i
);

localparam IDLE = 2'd0;
localparam REQUEST_SENT = 2'd1;
localparam WAIT_FOR_GRANT = 2'd2;
localparam TRANSACTION_COMPLETED = 2'd3;

// Internal state signals
reg [47:0] lsu_state = IDLE << (|WORDSIZE);
wire grant_requested = dmem_req_o & ex_if_ready_o;
wire load_data_granted = |({5{dmem_rready_i}} & dmem_rsp_rvalid_i);

assign wb_if_rvalid_o = load_data_granted;
module #(.LOC = "MEM_CTRL") mem_ctrl (
    input wire clk, rst_n, request, dmem_resp_ready, 
    output reg grant, data, data_valid);
    parameter LOC = MEM_CTRL;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            grant <= 0;
            data <= 0;
            data_valid <= 0;
        end else if (request && dmem_resp_ready) begin
            grant <= 1;
        end else if (data_valid) begin
            // do nothing since this request has been granted
        end else begin
            grant <= 0;
        end
    end
endmodule

// LSU State Machine
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
       lsu_state >= IDLE << |WORDSIZE;
    end else if (ex_if_req_i & ex_if_ready_o) begin
        if (&grant_requested || (ex_if_type_i[1:0] == 2'h2)) begin
            lsu_state <= TRANSACTION_COMPLETED << |WORDSIZE;
        end else if (dmem_rvalid_i && dmem_req_o) begin
            lsu_state <= WAIT_FOR_GRANT << |WORDSIZE;
        end else begin 
            lsu_state <= REQUEST_SENT << 2'd0;
	    case(ex_if_type_i[1:0])
	        2'h0: dmem_req_we_o = ex_if_we_i;
	        2'h1: if (ex_if_addr_offset_i[1:0] == 0)   // even address; use least-significant bytes
	                dmem_req_be_o = {1'b0, ex_if_wdata_i[7:0]};
	            else                                    // odd address; use most-significant bytes
	                dmem_req_be_o = {ex_if_wdata_i[15:8], 2'd0};
	        2'h2: dmem_req_addr_o = ex_if_addr_offset_i + ex_if_addr_offset_i[3];  // add a byte to address for read
	    endcase
            dmem_req_o <= 1;
        end
    end else begin
        lsu_state <= IDLE << |WORDSIZE;
    end
end

always @(*) begin
    case (lsu_state)
        IDLE: ex_if_ready_o = 1;
        WAIT_FOR_GRANT: ex_if_ready_o = dmem_rready_i & load_data_granted;
        REQUEST_SENT: ex_if_ready_o = grant_requested;
        TRANSACTION_COMPLETED: ex_if_ready_o = 1; // we're done
    endcase
end

// DMEM interface
assign dmem_req_addr_i[31:0] = dmem_req_wdata_o;
assign dmem_req_be_o[3:0]     = ex_if_wdata_i[7:4];
assign dmem_gnt_i             = (lsu_state == REQUEST_SENT);
module #(.LOC = "LOAD_STORE") load_store_req (
    input wire [31:0] addr,
    input wire [3:0] byte_enable,
    input wire write_data,
    output reg dmem_req_o,
    output reg [47:0] dmem_rsp_rdata
);
    parameter LOC = LOAD_STORE;

    // Set dmem_req_o high only for loads
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            dmem_req_o <= 0;
        end else if (addr != {32'h0}) begin
            dmem_req_o <= 1;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            dmem_rsp_rdata <= {28'h0, 4'bf};
        end else begin
            if (dmem_req_o) begin
                // Load transaction
                if (&dmem_gnt_i) begin
                    if (write_data != {32{1'b0}}) begin
                        dmem_rsp_rdata <= {32'h0, {4{1'b0}}, write_data};
                        #(.LOC = LOC) mem_ctrl.grant <= 1;
	                #(.LOC = "LOAD_MODULE") load.load <= 1; // notify Load Module that a load has been granted 
	            end else begin // read load is complete
	                dmem_rsp_rdata <= addr[31:0];
		        #(.LOC = LOC) mem_ctrl.grant <= 0;
		        #(.LOC = "LOAD_MODULE") load.load <= 0; // signal that Load Module can accept a new load instruction
                    end
                end else begin
                   dmem_rsp_rdata <= {32'hf, 4'bff}; // Dummy value if access is not granted
	         #(.LOC = LOC) mem_ctrl.grant <= 0;
                end
            end else begin // Store transaction
                dmem_rsp_rdata <= {32'h0, addr[1:0]};
	        #(.LOC = "LOAD_MODULE") load.load <= 0; // Load complete signal is not relevant here

	        for (byte_enable != 4'hf) begin #( .LOC="LOAD_STORE" )
                    load [byte_enable] <= dmem_req_wdata_o;
                end
            end
        end       // if (!rst_n)

    end 
endmodule

output.rtl/morse_encoder.sv:
module morse_encoder(
    input [7:0] ascii_in,
    output reg [9:0] morse_out,
    output reg [3:0] morse_length
);

always @* begin
    case(ascii_in) // Direct Mapping for Morse Code Encoding
        8'h41: begin morse_out = 10'b01; morse_length = 2; end
        8'h42: morse_out = 10'b1000; morse_length = 4;
        8'h43: morse_out = 10'b1010; morse_length = 4;
        8'h44: morse_out = 10'b100; morse_length = 3;
        8'h45: begin morse_out = 10'b0; morse_length = 1; end
        8'h46: morse_out = 10'b0010; morse_length = 4;
        8'h47: morse_out = 10'b110; morse_length = 3;
        8'h48: morse_out = 10'b0000; morse_length = 4;
        8'h49: begin morse_out = 10'b00; morse_length = 2; end
        8'h4A: morse_out = 10'b0111; morse_length = 4;
        8'h4B: morse_out = 10'b101; morse_length = 3;
        8'h4C: morse_out = 10'b0100; morse_length = 4;
        8'h4D: begin morse_out = 10'b11; morse_length = 2; end
        8'h4E: morse_out = 10'b10; morse_length = 3;
        8'h4F: morse_out = 10'b111; morse_length = 3;
        8'h50: morse_out = 10'b0110; morse_length = 4;
        8'h51: morse_out = 10'b0111; morse_length = 4;
        8'h52: morse_out = 10'b010; morse_length = 3;
        8'h53: begin morse_out = 10'b000; morse_length = 3; end
        8'h54: morse_out = 10'b001; morse_length = 4;
        8'h55: morse_out = 10'b011; morse_length = 4;
        8'h56: morse_out = 10'b00001; morse_length = 4;
        8'h57: morse_out = 10'b011; morse_length = 3;
        8'h58: morse_out = 10'b1101; morse_length = 4;
        8'h59: morse_out = 10'b1011; morse_length = 4;
        8'h5A: morse_out = 10'b1100; morse_length = 4;
        default: begin morse_out = 10'b0; morse_length = 0; end
    endcase
end

always @* begin
    if(ascii_in >= `ASCII '0') begin // ASCII to Morse Code mapping for digits 0-9
        case(ascii_in - `ASCII '0' + 2)
            3: morse_out = 10'b10000;
            4: morse_out = 10'b01111;
            5: morse_out = 10'b00111;
            6: morse_out = 10'b01000;
        endcase
    end else begin // Default case - Morse code is reset to zeros
        morse_out = 10'b0;
    end
end

always @* begin
    morse_length = ascii_in >= `ASCII 'A' && ascii_in <= `ASCII 'Z' ? 4 : ascii_in >= `ASCII '0' && ascii_in <= `ASCII '9' ? 5 : morse_length;
end

endmodule

output.rtl/packet_controller.sv:
module packet_controller(
    input clk,
    input rst,
    // RX Interface
    input rx_valid_i,
    input [7:0] rx_data_8_i,
    // TX Interface
    output reg tx_start_o,
    output reg [7:0] tx_data_8_o,
    output reg tx_done_tick_o);

    parameter S_IDLE = 2'd0;
    parameter S_GOT_8_BYTES = 2'd1;
    parameter S_RECV_CHECKSUM = 2'd2;
    parameter S_BUILD_RESPONSE = 2'd3;
    parameter S_SEND_FIRST_BYTE = 2'd4;
    parameter S_RESPONSE_READY = 2'd5;

    reg [1:0] state;

    always @(posedge clk) begin
        if (rst) begin
            // Reset all values to initial state
            state <= S_IDLE;
            tx_start_o <= 0;
            tx_data_8_o <= 8'h00;
            tx_done_tick_o <= 1'b0;
        end
        else begin
            case (state)
                S_IDLE: begin
                    // Wait for 8 bytes to accumulate in the buffer
                    if (rx_valid_i) begin
                        tx_data_8_o <= rx_data_8_i;
                        state <= S_GOT_8_BYTES;
                    end
                end
                S_GOT_8_BYTES: begin
                    // Check the header and compute the checksum
                    if (rx_data_8_i == 8'hd4) begin
                        // Expected header (BACD), prepare for response
                        tx_start_o <= 1;
                        state <= S_RECV_CHECKSUM;
                    end
                end
                S_RECV_CHECKSUM: begin
                    // Validate the checksum
                    if (
                        rx_data_8_i == 8'hc4 &&
                        tx_data_8_o[7:0] + rx_data_8_i == 8'h0
                       ) begin
                        // Valid response, proceed to compute result
                        state <= S_BUILD_RESPONSE;
                    end
                    else begin
                        // Invalid header or checksum mismatch, reset FSM
                        tx_start_o <= 0;
                        tx_data_8_o <= 8'h00;
                        state <= S_IDLE;
                    end
                end
                S_BUILD_RESPONSE: begin
                    // Prepare the outgoing response packet
                    if (rx_data_8_i == 8'hc4) begin
                        // Received expected checksum, complete computation
                        state <= S_SEND_FIRST_BYTE;
                    end
                end
                S_SEND_FIRST_BYTE: begin
                    // Initiate response transmission by sending the first byte
                    if (tx_done_tick_o) begin
                        tx_data_8_o <= 8'hab;
                        state <= S_RESPONSE_READY;
                    end
                end
                S_RESPONSE_READY: begin
                    // Handle the remaining response transmission
                    if (tx_done_tick_o) begin
                        tx_data_8_o <= tx_data_8_o[7:0] + rx_data_8_i;
                        tx_start_o <= 1'b1;
                        tx_data_8_o[7:0] <= tx_data_8_o[7:0] + 1; // increment checksum
                        state <= S_RESPONSE_READY;
                    end
                end
            endcase
        end
    end
endmodule

output.rtl/perceptron_gates.sv:
module gate_target (
    input [1:0] gate_select,
    output reg o_1,
    output reg o_2,
    output reg o_3,
    output reg o_4
);

   always @ (gate_select) begin
      case(gate_select)
         2'd0 : begin // AND GATE
                  o_1 = {4'd1, -4'd1, -4'd1};
                  o_2 = {4'd1, 4'd1, 4'd1};
      end
         2'd1 : begin // OR GATE
                  o_1 = {-4'd1, 4'd1, 4'd1, 4'd1};
      end
         2'd2 : begin // NAND GATE
                  o_1 = {4'd1, 4'd1, 4'd1, -4'd1};
      end
         2'd3 : begin // NOR GATE
                  o_1 = {-4'd1, -4'd1, -4'd1,-4'd1};
      end
         default: begin
                    o_1 = 0;
                end
      endcase
   end
endmodule

module perceptron_gates (
    input clk,
    input rst_n,
    input [3:0] x1,
    input [3:0] x2,
    input signed [3:0] threshold,
    input learning_rate,
    output reg signed [3:0] percep_w1,
    output reg signed [3:0] percep_w2,
    output reg signed [3:0] percep_bias,
    output reg [3:0] present_addr,
    output reg stop,
    output reg [2:0] input_index,
    output reg [3:0] y_in,
    output reg [3:0] y
);

parameter INITIALIZED = 4'b1001;
parameter MICROCODE_SIZE = 5'd6;

reg [MICROCODE_SIZE-1:0] microcode;
reg [2:0] gate_target;
wire [3:0] o1,o2,o3,o4;
wire signed [7:0] yt;
wire signed [7:0] yyt;
wire signed [7:0] yn;
wire signed [3:0] wt1_upd, wt2_upd, bias_upd;
wire signed [3:0] percep_w1_update, percep_w2_update, percep_bias_update;
reg [4'b31:0] counter;
reg [MICROCODE_SIZE-1:0] next_microcode;
reg stop_tmp, rst_n_r;
wire done, start;

assign y = yyt[7:0];
assign y_in = {4'b0, yt[7:3]};

assign o1 = gate_target[0] ? o1 : 4'd1;
assign o2 = gate_target[1] ? o2 : 4'b0;
assign o3 = gate_target[2] ? o3 : 4'b0;
assign o4 = gate_target[3] ? o4 : 4'b0;

assign gate_target = {x2[3], x1};

wire xor_y = |yt[7:6]; // y is a treshold crossed???

gate_target inst(.gate_select(gate_target), .o_1(o1),  .o_2(o2));
gate_target inst2(.gate_select(gate_target), .o_3(o3), .o_4(o4));

assign yyt = {xor_y, 3'b0, threshold[7:6], threshold};
assign yn = yt + {5'd0, o1, o2, o3}*learning_rate;

micrcode inst (
    .clk(clk),
    .rst_n(rst_n_r),
    .present_addr(present_addr),
    .next_microcode(next_microcode),
    .counter(counter),
    .start(start),
    .done(done) // Done is low when micro-op is done.
);

always @ (posedge clk) begin
    rst_n_r <= rst_n;
    if (!rst_n)
        present_addr <= 0;
    start <= present_addr == next_microcode;
end

always @ (*) begin
    case(present_addr[2:1])
        2'd0 : counter = INITIALIZED;
        2'b10, 2'b11 : counter = 3'd7;
        default : counter = 3'd5;
    endcase
end

always @ (*) begin
    case(present_addr[1:0])
        2'b0x : microcode = percep_w1_update | (percep_bias_update ? {1'b1, 4'b0} : {5'd0} )<<3; // wt1 upd, bias update
        2'b1x : begin
              if(percep_bias_update)
                  microcode = (learning_rate > 0 ? percep_bias_update : {5'd0})<<3 | wt2_upd|(learning_rate > 0 ? 1'b1 : 1'b0); // bias update, wt2 upd
                                                                                                                else
                 microcode = percep_w2_update <<3 ;// wt2 update, only if percep_bias_update is not set...
           end
        2'b13 : microcode = (learning_rate > 0 ? percep_w1_update : {5'd0})<<2; // Wt, only if y[7] is xor.
                                                                                            // Note : bias upd & wt2 upd was tested but fails !!!
        2'b14 : microcode = (learning_rate > 0 ? percep_w1_update : {5'd0})<<3 ; // Wt, only if y[7:6] is 2'b0x
                                                                            // Note : bias upd & wt1_upd was tested but fails !!!
        2'b15 : microcode = (learning_rate > 0 ? percep_w1_update : {5'd0})<<4 ; // Wit, only if y[7:6] is 2'b1x (so xor_y was 0)
                                                                             // Note : bias upd & wt1_upd was tested but fails !!!
        2'b16 : microcode = {6{learning_rate}};// Initial, Only when perceptron got fully trained...
        default : microcode = ~128 ? {3'd0, y[7], -1} : 4'bx; // 4'b? to mark op as done.
    endcase
end

assign done = next_microcode == present_addr && present_addr != microcode;
assign percep_w1_update = (microcode[3:0] == present_addr[2:0]) ? (5'd0) : ((present_addr[2:1] == 2'b0x) ? {4'b1, o1, -o1} : {4'b1, 4'b0}) <<3;
assign percep_w2_update = (microcode[7:4] == present_addr[2:0]) ? (~4'd0) : ((present_addr[2:1] == 2'b1x || present_addr[2:1] == 2'b13) ? {4'b1, xor_y, ~xor_y} << 3 : (microcode[7:4][0] ? (present_addr[2:1] == 2'b0x ? {3'd0, o2} : {{~o3}, o2}) : o3) <<3 });
module percep_bias_upd (
    input clk,
    input rst_n,
    output reg signed [1:0] stopped
);
    assign yt = {percep_w1, percep_w2};
    sub_module inst(.clk(clk), .rst_n(rst_n), .yt(yt), .yn(y), .threshold(threshold));
    always @ (posedge clk) begin
        if (!rst_n)
            percep_bias <= 4'd1;
        else if (!(~|present_addr)) // Perceptron got fully trained, Stop.
            percep_bias <= 4'd0;    
    end
endmodule

module sub_module (
    input clk, 
    input rst_n, 
    output reg signed [7:0] yt, 
    output reg signed [7:0] y, 
    input signed [7:0] threshold
);
    always @ (posedge clk) begin
        if (!rst_n) begin
            yt <= 8'b1111_1111; // Initial state. Percepton will not be trained...
        end
        else if ({xor_y, o1} > {xor_y, threshold})
            yt <= 8'b1111_1110; // First layer of gates
    end
endmodule

output.rtl/perfect_squares_generator.sv:
module perfect_squares_generator(
    input clk,
    input reset,
    output reg [31:0] sqr_o
);

reg [31:0] count;

always @(posedge clk or negedge reset) begin
    if (!reset) begin
        count <= 1;
        sqr_o <= 1;
    end else if (count == 32'hFFFFFFFF) begin
        count <= 0;
        sqr_o <= 0;
    end else if (sqr_o >= count*count) begin
        count <= count + 1;
    end else begin
        sqr_o <= sqr_o + 1;
    end
end

endmodule

output.rtl/piso_8bit.sv:
module piso_8bit(clk, rst, serial_out);

input clk;
input rst;
output reg serial_out;

reg [7:0] tmp;

always @(posedge clk or negedge rst) begin
    if (~rst) begin // Asynchronous active LOW reset
        tmp <= 8'b0000_0001;
        serial_out <= 1'b0;
    end
    else begin
        if (tmp == 8'b1111_1111) // Increment the value after every 8th clock cycle
            tmp <= 8'b0000_0000;
        else
            tmp <= tmp + 8'h1; // Increment the value by one when 3 bits are transmitted
         serial_out <= (!tmp[7]) ? 1'b1 : 1'b0;
    end
end

endmodule

output.rtl/secure_read_write_register_bank.v:
module secure_read_write_register_bank (
    input [p_addr_width-1:0] i_addr,
    input [p_data_width-1:0] i_data_in,
    input i_read_write_enable,
    input i_capture_pulse,
    input i_rst_n,
    output reg [p_data_width-1:0] o_data_out
);

parameter p_addr_width = 8;
parameter p_data_width = 8;
parameter p_unlock_code_0 = 8'hAB;
parameter p_unlock_code_1 = 8'hCD;

(* LOCKED *) reg [p_data_width-1:0] reg_bank [(2**p_addr_width)-2:0]; // all registers locked initially except FIRST TWO (index = 0 & index = 1)
reg [p_data_width-1:0] unlock_code_0;
reg [p_data_width-1:0] unlock_code_1;
reg [p_addr_width-1:0] addr_read; // read address
reg unlock = 0;

always @(negedge i_rst_n) begin
    if (~i_rst_n) begin
        o_data_out <= #1 0;
        reg_bank <= #1 {(p_addr_width-2){1'b0}};
        addr_read <= #1 p_addr_width{-1};
        unlock <= #1 0;
        unlock_code_0 <= #1 p_unlock_code_0;
        unlock_code_1 <= #1 p_unlock_code_1;
    end
end

always @(posedge i_capture_pulse) begin
    if (~i_rst_n) begin
        // on low i_rst_n lock register bank
        reg_bank <= #1 {(p_addr_width-2){1'b0}};
        o_data_out <= #1 0;
        addr_read <= #1 p_addr_width{-1};
        unlock <= #1 0;
    end else begin
        case (i_read_write_enable)
            1: // read
                if ((p_data_width-2):&addr_read[p_addr_width-(1+p_data_width)])
                    addr_read <= #1 addr_read - (p_data_width);
                else begin
                    o_data_out <= #1 reg_bank[addr_read];
                end
            0: // write
                if (!unlock) begin // not unlocked
                    if ((i_addr == 0)&&(i_data_in == p_unlock_code_0)) begin
                        unlock_code_1 <= #1 i_data_in; // this will happen only once, otherwise lock again.
                        unlock <= #1 1; // unlocked!
                    end else if ((i_addr == 1)&&(i_data_in == p_unlock_code_1)) begin
                        unlock <= #1 1; // unlocked
                    end else begin // default lock state during write
                        unlock <= #1 0;
                    end
                end else if ((i_addr >= p_data_width)||(i_addr < 0)) begin 
                    reg_bank[i_addr] <= #1 i_data_in;
                end
        endcase
    end
end

always @ (negedge i_capture_pulse or negedge i_rst_n) begin
    if (!i_rst_n) begin
        o_data_out <= #1 0;
    end else if (i_addr == 2'd0 && !i_read_write_enable) begin // write to address zero
       o_data_out <= #1 i_data_in;
    end else if (i_rst_n || !unlock) begin // reset, lock or not unlocked
        o_data_out <= #1 0;
    end else if ((i_addr >= p_data_width)&&(~reg_bank[0])) begin // it's a write on an address for which we have already written something
        reg_bank[i_addr] <= #1 i_data_in;
    end else begin
       o_data_out <= #1 o_data_out;
    end
end

always @ (posedge i_capture_pulse or negedge i_rst_n) begin
    if (!i_rst_n) begin // reset: just in case...
        unlock <= #1 0;
    end else if ((i_addr==1) && !unlock) begin // write to address one
       unlock <= #1 ((i_data_in == p_unlock_code_1)? 1 : 0); // update only if we are not already unlocked
    end else if (unlock) begin
        unlock <= #1 ~unlock; // reset lock, because writing to unlock condition doesn't really unlock
    end
end

always @ (posedge i_capture_pulse or negedge i_rst_n) begin
    if (!i_rst_n) begin // reset: just in case...
        o_data_out <= #1 0;
    end else if ((!unlock)&&(!i_addr)) begin // it was a write to address zero or one
       o_data_out <= #1 i_data_in ? {p_data_width{1'bx}} : {p_data_width{1'b0}}; // it would be an error if the first bit were 1 (which means that an unlock code was written, but it is not)
    end else if (i_addr == 2'd0 && !lock) begin // address zero has been read
        o_data_out <= #1 i_read_write_enable ? o_data_out : reg_bank[i_addr]; // if we enable read only and the user is reading it would go to 0 because of the reset that follows
    end else if (i_read_write_enable) begin
        addr_read <= #1 i_addr; // we do not want this, but there's still nothing meaningful in it at this time.
 module with addressable read, but not write space  (secure_accessible_register);
    end
end

